Rule.Source:
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;
import sailpoint.object.Application;
import sailpoint.object.Link;
import sailpoint.object.Identity;
import sailpoint.tools.Util;
import sailpoint.api.IdentityService;
import sailpoint.rapidapponboarding.logger.LogEnablement;

{
  Log tlog = LogFactory.getLog("rule.ToyotaOrgLDAPAtldapuserRoleAssignment");    
  LogEnablement.isLogTraceEnabled(tlog, "TMNA-TOARA-001-Entering Toyota Org LDAP Atldapuser Role Assignment.");  

  boolean exclude = false;
  try {
    IdentityService service = new IdentityService(context);
    String attrValue = identity.getAttribute("supOrgFuncCode");
    String workGroupName = "AT-LDAP Excluded Users";
    Application orgLdap = null;
    List orgLdapLinks = null;
    Identity exclusionWorkGroup  = context.getObjectByName(Identity.class,workGroupName);

    if ( Util.nullSafeCaseInsensitiveEq(attrValue, "SO-226923")) {
      if (null != exclusionWorkGroup && exclusionWorkGroup.isWorkgroup() && !identity.isInWorkGroup(exclusionWorkGroup) ) {
        orgLdap = context.getObjectByName(Application.class,"Org LDAP");
        if ( null != orgLdap){
          orgLdapLinks = service.getLinks(identity,application);
          if ( Util.nullSafeSize(orgLdapLinks) > 0 ) {
            if ( !orgLdapLinks.get(0).isDisabled() ) {
              exclude = true;
            }
          }
        }
      }
    }
  } catch (Exception e) {
    LogEnablement.isLogTraceEnabled(tlog, "TMNA-TOARA-002-ERROR for User: " +identity.getName()+ "Error Message: An exception was thrown while attempting to process Toyota Org LDAP Atldapuser Role Assignment " + e.toString());      
  } 
  LogEnablement.isLogTraceEnabled(tlog, "TMNA-TOARA-003-Exiting Toyota Org LDAP Atldapuser Role Assignment.");  
  return exclude;
}
